function maxPower(s) {
    let maxPower = 0, currentPower = 1;

    for (let i = 1; i < s.length; i++) {
        if (s[i] === s[i-1]) {
            currentPower++;
        } else {
            maxPower = Math.max(maxPower, currentPower);
            currentPower = 1;
